"""
christ | Numbers 1-2 | The census of Israel and the camp arrangement
Run: python3 scripts/zc-christ-numbers-1-2.py

Ch 1: The first census of Israel's fighting men — every tribe, every name, every number.
      Christological lens: enrollment in the book of life; the army of God; Levi's exclusion
      pointing to the priestly order set apart for sanctuary service.

Ch 2: The camp arranged around the tabernacle — four quadrants, Judah leading east,
      the tabernacle at center. Christological lens: Christ as center of his people;
      the tribal banners; Revelation's 12-tribe structure.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}


def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


NUMBERS_CHRIST = {
    "1": {
        "1": "<p>YHWH speaks to Moses in the tent of meeting in the wilderness of Sinai on the first day of the second month of the second year after the exodus. The precision of the date situates the census at a specific moment in redemptive history — one year and one month after the exodus, the redeemed community is now formally mustered as YHWH's army. The tent of meeting as the venue of divine speech foreshadows Christ, in whom God's word and God's dwelling meet: 'the Word became flesh and dwelt (<i>eskēnōsen</i>, tabernacled) among us' (John 1:14).</p>",
        "2": "<p>'Take a census of all the congregation of the people of Israel.' The command to count every Israelite by name and family is the act of a God who knows each person individually. Jesus applies this to the new covenant: 'I am the good shepherd. I know my own and my own know me' (John 10:14); and 'rejoice that your names are written in heaven' (Luke 10:20). The Sinai census is the earthly type of the heavenly enrollment.</p>",
        "3": "<p>'Every man in Israel who is able to go to war.' The census is a military muster — YHWH is enrolling his people as an army. Paul applies this military framing to the church: 'Put on the whole armor of God, that you may be able to stand against the schemes of the devil' (Eph 6:11). The fighting men of Israel are the type; the church militant is the antitype — every member enrolled and equipped for spiritual warfare.</p>",
        "4": "<p>One man from each tribe to assist Moses and Aaron — each a head of his father's house. The tribal representative structure prefigures the apostolic structure of the church: twelve tribes become twelve apostles, each representing the fullness of Israel reconstituted around Christ (Matt 19:28: 'you who have followed me will also sit on twelve thrones, judging the twelve tribes of Israel').</p>",
        "5": "<p>Elizur son of Shedeur heads Reuben's representatives. Reuben, Jacob's firstborn (Gen 29:32), lost the firstborn's prerogative through sin (Gen 49:3–4). Christ, the true firstborn (<i>prōtotokos</i>) of all creation (Col 1:15) and from the dead (Col 1:18), restores what human firstborns forfeited — not through tribal descent but through resurrection.</p>",
        "6": "<p>Shelumiel son of Zurishaddai for Simeon. Simeon and Levi were rebuked together in Jacob's blessing (Gen 49:5–7); Levi was redeemed through the Levites' zeal at the golden calf (Exod 32:26–29) and here excluded from the fighting census. Simeon's tribe persists in the census but will suffer massive reduction by Numbers 26 — a warning that tribal identity alone does not guarantee perseverance in the covenant.</p>",
        "7": "<p>Nahshon son of Amminadab for Judah. Nahshon is the most significant tribal representative in the list: he appears in the genealogy of Christ (Matt 1:4: 'Ram the father of Amminadab, and Amminadab the father of Nahshon'). The messianic line runs through Judah's census representative, connecting the wilderness military muster to the incarnation of Israel's king.</p>",
        "8": "<p>Nethanel son of Zuar for Issachar. Issachar's territory in Galilee becomes significant in Christ's ministry: the tribe whose blessing evokes contentment in the land inhabits the region where Christ will announce 'Come to me, all who labor and are heavy laden, and I will give you rest' (Matt 11:28) — the true Sabbath-rest that Issachar's restful name dimly promised.</p>",
        "9": "<p>Eliab son of Helon for Zebulun. Zebulun's territory becomes the land of Jesus' ministry: 'The land of Zebulun and the land of Naphtali... the people dwelling in darkness have seen a great light' (Matt 4:15–16, citing Isa 9:1–2). The census representative of Zebulun stands at the beginning of the territory where Christ will begin his public ministry.</p>",
        "10": "<p>Elishama son of Ammihud for Ephraim; Gamaliel son of Pedahzur for Manasseh. The sons of Joseph receive double representation through Ephraim and Manasseh — Jacob's crossing of his hands to bless the younger Ephraim over Manasseh (Gen 48:14–19) prefigures Christ's reversal of the expected order: 'the last will be first, and the first last' (Matt 20:16). The younger inheriting the greater blessing is a recurrent type pointing to Christ the second Adam who surpasses the first.</p>",
        "11": "<p>Gamaliel son of Pedahzur for Manasseh. Manasseh's name means 'God has caused me to forget my hardship' (Gen 41:51) — Joseph's consolation word at the birth of his firstborn. The forgetting of hardship anticipates Paul: 'forgetting what lies behind and straining forward to what lies ahead, I press on toward the goal for the prize of the upward call of God in Christ Jesus' (Phil 3:13–14).</p>",
        "12": "<p>Abidan son of Gideoni for Benjamin. Benjamin, whose name was changed from Ben-oni (son of my sorrow) to Benjamin (son of the right hand) at his mother Rachel's death, is a type of Christ: born in sorrow yet seated at the right hand. The tribe of Benjamin will produce Paul, the apostle to the Gentiles, who is himself a type of Israel's conversion (Phil 3:5; Rom 11:1).</p>",
        "13": "<p>Ahiezer son of Ammishaddai for Dan. Dan's blessing in Gen 49:16–17 introduces the serpent imagery. Dan is later omitted from the 144,000 in Rev 7 (replaced by Manasseh), connected to Dan's adoption of idolatry (Judg 18). The tribe present in the Num 1 census and absent in Rev 7 is a sobering reminder that enrollment in the earthly census does not guarantee enrollment in the heavenly one.</p>",
        "14": "<p>Pagiel son of Ochran for Asher. Asher's name means 'happy/blessed' (Gen 30:13). Moses' blessing (Deut 33:24: 'Most blessed of sons is Asher') gives Asher a unique superlative. The Beatitudes of Jesus (Matt 5:3–12) begin with <i>makarios</i> (blessed/happy) — the deepest fulfillment of what Asher's name promised, now available to all who come to Christ.</p>",
        "15": "<p>Eliasaph son of Deuel for Gad. Gad's name means 'good fortune' (Gen 30:11). The warrior-tribe of good fortune stands in the secondary southern camp (Num 2:14–15), a reminder that fortune and power in the covenant community are received gifts, not tribal achievements. God's grace is the good fortune underlying every tribal blessing.</p>",
        "16": "<p>Ahira son of Enan for Naphtali. Naphtali's territory at the Sea of Galilee is where Jesus calls fishermen to become fishers of men (Matt 4:18–22). The wrestling-tribe's lake becomes the scene of Christ's Galilean ministry — the census of fighting men finds its fulfillment in the summons to a different kind of warfare: 'Follow me, and I will make you fishers of men' (Matt 4:19).</p>",
        "17": "<p>Moses and Aaron take these designated men — 'called by name' (<i>niqˀvu bishemot</i>) — and assemble the whole congregation. The phrase 'called by name' is one of the OT's clearest images of divine election: each representative was named, not randomly selected. Jesus echoes this: 'I have manifested your name to the people whom you gave me out of the world' (John 17:6).</p>",
        "18": "<p>The assembly registers by ancestry on the first day of the second month. The genealogical registration is a covenant-identity procedure: belonging to Israel means belonging by birth to a specific family. The new covenant maintains this principle but redefines the birth: 'unless one is born again he cannot see the kingdom of God' (John 3:3). The census registers physical birth; the new covenant enrolls those born from above.</p>",
        "19": "<p>'As YHWH commanded Moses' — the census is divine work, not merely human administration. The counting of God's people is always a divine initiative: 'Even the hairs of your head are all numbered' (Matt 10:30). The Sinai census is the macrocosmic version of this microscopic divine enumeration of those who belong to Christ.</p>",
        "20": "<p>Reuben's descendants: the formula is identical for every tribe — genealogical claim, age qualifier (twenty years old and upward), fitness qualifier (able to go to war), number. The repetition is deliberate: each tribe receives identical dignity in the counting. In Christ, 'there is neither Jew nor Greek, slave nor free, male nor female' (Gal 3:28) — each is counted with equal value before God.</p>",
        "21": "<p>Reuben's total: 46,500. Reuben forfeited the firstborn blessing (Gen 49:3–4) through instability; his tribe never rises to prominence. The shadow of lost blessing on Reuben's number makes the census poignant: here is a tribe fully counted, fully present, but carrying the legacy of a forfeited destiny. Christ alone is the faithful firstborn who did not forfeit his inheritance (Heb 1:2–4).</p>",
        "22": "<p>Simeon's descendants registered. Simeon means 'YHWH has heard' (Gen 29:33). The name encodes Leah's awareness that her son was a divine response to her being unloved. In Christ, YHWH's hearing of human need reaches its ultimate form: 'God shows his love for us in that while we were still sinners, Christ died for us' (Rom 5:8) — not merely a hearing but a self-giving.</p>",
        "23": "<p>Simeon's total: 59,300. By Numbers 26, Simeon's tribe will fall to 22,200 — the most dramatic reduction of any tribe, traced directly to the Baal Peor apostasy (Num 25:14). No tribe in the census is guaranteed perseverance; the final count of the redeemed is God's work, not tribal momentum: 'he who endures to the end will be saved' (Matt 24:13).</p>",
        "24": "<p>Gad's descendants registered. Gad means 'a troop' or 'good fortune' (Gen 30:11). The tribe's warrior character is confirmed by their role as shock troops for the Canaan conquest. The good-fortune name and warrior reality of Gad point to the church: called to blessedness (<i>makarioi</i>, Matt 5:3–12) yet engaged in spiritual warfare (Eph 6:10–18).</p>",
        "25": "<p>Gad's total: 45,650. The consistent formula applied to every tribe gives each the same dignity. No tribe is dismissed with a lesser description; each is fully enumerated. The full accounting anticipates the complete number of the redeemed: 'a great multitude that no one could number, from every nation, from all tribes and peoples and languages' (Rev 7:9).</p>",
        "26": "<p>Judah's descendants registered. Judah means 'praise' (Gen 29:35). Jacob's blessing establishes Judah as the royal line: 'The scepter shall not depart from Judah... until tribute comes to him; and to him shall be the obedience of the peoples' (Gen 49:10). The census counts Judah as one tribe among twelve; history will reveal it as the tribe of David and of Christ — the tribe of praise bearing the king of praise.</p>",
        "27": "<p>Judah's total: 74,600 — the largest tribe in the census. The largest count belongs to the royal tribe, and Judah will march first (Num 2:3). In Rev 5:5, the Lion of the tribe of Judah opens the scroll that no one else can open. The census number is the first marker of Judah's preeminence that culminates in the incarnation of the world's king from this tribe.</p>",
        "28": "<p>Issachar's descendants registered. Issachar's later tradition of 'understanding the times' (1 Chr 12:32) marks them as discerners. Christ is the one in whom 'are hidden all the treasures of wisdom and knowledge' (Col 2:3) — the ultimate fulfillment of Issachar's discernment gifting, the one who fully understands all times and seasons.</p>",
        "29": "<p>Issachar's total: 54,400. The consistent counting through twelve tribes builds a comprehensive picture of a fully enumerated people. The completeness of the census — everyone counted, no one forgotten — is the OT image of pastoral care Christ exercises over his flock: 'He calls his own sheep by name and leads them out' (John 10:3).</p>",
        "30": "<p>Zebulun's descendants registered. The Galilean territory of Zebulun becomes the scene of Christ's early ministry: 'He went and lived in Capernaum by the sea, in the territory of Zebulun and Naphtali' (Matt 4:13). The tribe counted in the wilderness census inhabits the land where the Word will dwell among his people in human flesh.</p>",
        "31": "<p>Zebulun's total: 57,400. This closes the first six tribes (Reuben through Zebulun, the sons of Leah). The Leah tribes — historically the less-loved side of Jacob's family — are first in the march order. In Christ's economy, 'God chose what is low and despised in the world... to bring to nothing things that are, so that no human being might boast in the presence of God' (1 Cor 1:28–29).</p>",
        "32": "<p>Joseph's sons (Ephraim and Manasseh) registered. Joseph's double-portion inheritance (two tribes from one son) reflects Jacob's adoption of his grandsons (Gen 48:5). The doubling of Joseph's inheritance anticipates the double portion of the true firstborn: Christ inherits all things (Heb 1:2), and those in him receive an inheritance 'imperishable, undefiled, and unfading, kept in heaven for you' (1 Pet 1:4).</p>",
        "33": "<p>Ephraim's total: 40,500. Ephraim, despite being the younger twin grandson (Jacob crossed his hands to bless the younger first), received the primary blessing. The younger-inheriting-greater pattern — Abel, Isaac, Jacob, Joseph, Ephraim — finds its culminating expression in Christ, the 'last Adam' (1 Cor 15:45) who inherits what the first Adam lost.</p>",
        "34": "<p>Manasseh's total: 32,200 — smaller than Ephraim's, confirming Jacob's blessing hierarchy. The reversal of natural birth order encodes the theological principle Paul cites: 'the older will serve the younger... not because of works but because of him who calls' (Rom 9:12). God's elective purposes do not follow human expectations.</p>",
        "35": "<p>Benjamin's descendants registered. Benjamin, born at Rachel's death (Ben-oni → Benjamin, son of the right hand, Gen 35:18), carries both grief and glory in his name. The tribe will produce Paul — who begins in opposition (persecuting the church) and ends in the service of God's purposes (apostle to the Gentiles, Phil 3:5; Rom 11:1), a type of Israel's own future conversion.</p>",
        "36": "<p>Benjamin's total: 35,400. The smallest of the Rachel tribes, Benjamin occupies a position that belies its destiny: from this tribe comes the man who will carry the gospel to the western ends of the earth. The least may bear the furthest-reaching commission — the pattern of Christ's own calling of the Twelve (fishermen, not priests or scribes).</p>",
        "37": "<p>Benjamin's total confirmed: 35,400. The twice-noted numbers for each tribe signal the solemn legal character of the registration. Being enrolled in YHWH's army is a serious matter — 'The Lord knows those who are his' (2 Tim 2:19) requires a corresponding 'Let everyone who names the name of the Lord depart from iniquity.'</p>",
        "38": "<p>Dan's descendants registered. Dan's territory in the north became the site of Israel's first major idolatry (Judg 18:30). Dan's absence from the 144,000 in Rev 7 is connected to this apostasy tradition. The tribe present in Num 1 and absent in Rev 7 is a sobering reminder that enrollment in the earthly census does not guarantee enrollment in the heavenly one — perseverance in covenant faithfulness, not initial registration, determines the final count.</p>",
        "39": "<p>Dan's total: 62,700 — one of the larger tribes. Numbers and final outcome are not correlated in covenant faithfulness: large tribes (Simeon, Dan) fail; smaller tribes (Judah, Benjamin) carry the messianic and apostolic lines. 'Not by might, nor by power, but by my Spirit, says the LORD of hosts' (Zech 4:6).</p>",
        "40": "<p>Asher's descendants registered. Moses' blessing gives Asher the unique superlative 'most blessed of sons' (Deut 33:24). The Beatitudes of Jesus (Matt 5:3–12) are the new covenant Asher-blessing: 'Blessed are the poor in spirit... blessed are the meek... blessed are the pure in heart' — the blessedness that Asher's name announced finds its full content in the person and teaching of Christ.</p>",
        "41": "<p>Asher's total: 41,500. The northern Asherite territory along the fertile coast produces abundant olive oil — the substance used to consecrate priests and kings in Israel. The oil of gladness that Christ receives above his companions (Ps 45:7; Heb 1:9) is the ultimate fulfillment of Asher's olive-oil abundance: the one who is anointed (<i>Christos</i>) beyond all others.</p>",
        "42": "<p>Naphtali's descendants registered. Moses' blessing (Deut 33:23) is the most lyrical: 'satisfied with favor, and full of the blessing of the LORD, possess the lake and the south.' The lake is the Sea of Galilee — the site of Jesus' first Galilean healings and the calling of the fishermen-disciples (Matt 4:13–22; John 21:1–14). The census of Naphtali counts the people whose tribal lake becomes the stage for Christ's early signs.</p>",
        "43": "<p>Naphtali's total: 53,400. The last tribe in the main census list. The tribe of Naphtali's territory at the Sea of Galilee is the location where Christ calls the first disciples to become fishers of men (Matt 4:18–22) — the military census of fighting men becomes, in its fulfillment, a summons to the spiritual warfare of gospel proclamation.</p>",
        "44": "<p>These are those registered by Moses, Aaron, and the twelve leaders of Israel — one man for each father's house. Twelve census leaders represent twelve tribes. In Rev 21:14, the new Jerusalem has 'twelve foundations, and on them were the twelve names of the twelve apostles of the Lamb.' The twelve census leaders of Num 1 are the OT shadow of the twelve apostles — one man representing each segment of God's people.</p>",
        "45": "<p>All the registered men of Israel, twenty years old and upward, able to go to war: 603,550. Paul applies the wilderness generation to the church: 'our fathers were all under the cloud, and all passed through the sea, and all were baptized into Moses' (1 Cor 10:1–2). The 603,550 baptized into Moses in the sea are the type of those baptized into Christ. The Sinai census is the forerunner of the eschatological count: 'a great multitude that no one could number' (Rev 7:9).</p>",
        "46": "<p>603,550 — repeated for emphasis. The completeness of the count mirrors the completeness of Christ's knowledge of his own: 'I know my own' (John 10:14). No one enrolled in the heavenly census falls through the cracks: 'All that the Father gives me will come to me, and whoever comes to me I will never cast out' (John 6:37).</p>",
        "47": "<p>The Levites were not registered among the fighting men. The exclusion is a positive distinction — they are set apart for a different service. The principle recurs in the NT: some are called to specific ministries distinct from the general calling of the church. The Levitical exclusion from the military census foreshadows the NT distinction within one body: 'Are all apostles? Are all prophets?... But earnestly desire the higher gifts' (1 Cor 12:29–31).</p>",
        "48": "<p>YHWH's direct instruction to Moses not to enroll the Levites in the fighting census. The Levites have a different calling that must not be conflated with military service. The priestly calling in Christ likewise has its own character: 'You are a chosen race, a royal priesthood... a people for his own possession' (1 Pet 2:9) — the church's primary identity is priestly, not merely military, though it also fights.</p>",
        "49": "<p>The Levites are not to be numbered among the Israelites. Their separate census (Num 3) registers them differently — not by fighting age but by age of sanctuary service. The two censuses reflect two purposes: military readiness (fighting men) and sanctuary service (Levites). Christ is both — the warrior who conquers and the priest who intercedes — and the church participates in both callings.</p>",
        "50": "<p>The Levites are appointed over the tabernacle of testimony — wherever it travels, they travel with it. The inseparability of the Levites from the tabernacle is the OT image of the inseparability of Christ's people from his presence: 'I am with you always, to the end of the age' (Matt 28:20) — the promise of continuous divine accompaniment that the Levites' permanent assignment to the tabernacle embodied.</p>",
        "51": "<p>Any outsider who comes near the tabernacle shall be put to death. The guarding of the tabernacle from unauthorized access mirrors the holiness-boundary theology throughout Numbers. Christ is both the tabernacle (God's dwelling among us) and the one who grants access — 'through him we both have access in one Spirit to the Father' (Eph 2:18). Access remains through him, not around him.</p>",
        "52": "<p>The Israelites camp each by his own standard, with his own company — the tribal banner system. The organized camping by standard creates a visible order of people around the central sanctuary. The church's order around Christ as its center echoes this: 'He is the head of the body, the church' (Col 1:18) — the whole body arranged around the head, not randomly assembled.</p>",
        "53": "<p>The Levites camp around the tabernacle so that wrath will not fall on the congregation. The Levitical buffer zone performs an atoning-protective function — the Levites stand between YHWH's holiness and the people's potential encroachment. Christ is the ultimate fulfillment of this protective mediation: 'There is one mediator between God and men, the man Christ Jesus' (1 Tim 2:5).</p>",
        "54": "<p>The Israelites do all that YHWH commanded Moses. The compliance formula closes the census chapter with full obedience. The completed Sinai census — 603,550 fighting men known by name, counted, and deployed — is the OT's image of Christ's flock: 'The Lord knows those who are his' (2 Tim 2:19), and none is missing from the divine account.</p>",
    },
    "2": {
        "1": "<p>YHWH speaks to Moses and Aaron about the camp arrangement. The divine origin of the camp layout means the organization of Israel around the tabernacle is revealed order, not human convention. Christ is the center of the new covenant assembly not by human organization but by divine appointment: 'He is before all things, and in him all things hold together' (Col 1:17).</p>",
        "2": "<p>'The people of Israel shall camp each by his own standard (<i>degel</i>), with the banners of their fathers' houses.' The word <i>degel</i> (standard, banner) appears in Song of Songs 2:4: 'His banner over me was love.' The banner of the Beloved over his bride is the eschatological fulfillment of Israel's tribal standards — every banner ultimately displays the love of the divine king over his people.</p>",
        "3": "<p>Judah camps on the east — toward the sunrise — and leads the march. The east is the direction of sunrise, of Eden's entrance (Gen 3:24), and of the glory's return (Ezek 43:2). Judah leading from the east carries the sunrise symbolism of the messianic hope: 'the sun of righteousness shall rise with healing in its wings' (Mal 4:2). Judah, as the royal tribe, leads from the direction of rising light.</p>",
        "4": "<p>Judah's force: 74,600 under Nahshon son of Amminadab, who is in the messianic genealogy (Matt 1:4; Ruth 4:20). The leader of the largest tribe in the first census commands the vanguard of the march — and his lineage produces the king of all kings. Nahshon's position at the head of the march traces the messianic line forward to Christ leading his people into the true promised land.</p>",
        "5": "<p>Issachar camps next to Judah on the east side. The pairing of Issachar with Judah in the marching order reflects the tribal clustering: Judah, Issachar, and Zebulun form the eastern company. The pattern of clustering will recur in the tribal gates of the new Jerusalem (Rev 21:12–13), where all twelve tribes have a named gate permanently preserved in the city of God.</p>",
        "6": "<p>Issachar's force: 54,400 under Nethanel son of Zuar. The commander's name (<i>Nethanel</i> = 'God has given') carries a Christological hint: God's gift to his people is the deeper reality behind every numbered tribe. 'Thanks be to God for his inexpressible gift!' (2 Cor 9:15) — the gift that all tribal leadership dimly anticipated.</p>",
        "7": "<p>Zebulun camps next, completing the eastern cluster. Zebulun's territory will be Jesus' home region (Matt 4:13–16). The eastward placement of the tribe of Galilee — sunrise direction — is typologically apt: the honor of Zebulun's territory is the honor of being where the Light of the world dwelt in human flesh (John 1:14).</p>",
        "8": "<p>Zebulun's force: 57,400. The three eastern tribes combined (74,600 + 54,400 + 57,400 = 186,400) form the largest marching company. The east — sunrise direction, Judah's position — fields the greatest force. The gospel will go out in all directions, but Numbers places the greatest concentration of Israel's strength in the direction of the promised inheritance and the rising light.</p>",
        "9": "<p>The total of the eastern standard: 186,400 — they march first. Those who march first carry the promise forward. Christ the Lion of Judah marches at the head of his people into the promised inheritance: 'I go to prepare a place for you... I will come again and will take you to myself' (John 14:2–3).</p>",
        "10": "<p>Reuben camps on the south side. South in Hebrew geography is also the direction toward the Negev and the wilderness. Reuben on the south — the firstborn who lost his prerogative — occupies the secondary position. The firstborn's displacement in the camp order (Reuben south, Judah east/first) is the spatial encoding of the theological principle: the natural first yields to the divinely chosen.</p>",
        "11": "<p>Reuben's force: 46,500. Reuben commands the south but does not lead the march — Judah leads. The one who should have been first is second. The firstborn's displacement makes the camp a spatial theology of election: YHWH's choice, not birth order, determines the vanguard. Christ the 'last Adam' (1 Cor 15:45) is YHWH's ultimate choice to lead the people into inheritance.</p>",
        "12": "<p>Simeon camps with Reuben's standard on the south. Simeon ('YHWH has heard') is placed near Reuben in the march — the two Leah sons whose blessings were most negative (Gen 49:3–7) grouped together. Yet YHWH heard Leah's unloved condition (Gen 29:33), and Christ's hearing of the unloved echoes Simeon's name: 'Call upon me in the day of trouble; I will deliver you' (Ps 50:15).</p>",
        "13": "<p>Simeon's force: 59,300 under Shelumiel son of Zurishaddai. Shelumiel's name (<i>shelumi-el</i> = 'God is my peace') is the western counterpart to Simeon's divine-hearing name. 'He himself is our peace' (Eph 2:14) — the one in whom YHWH's hearing and YHWH's peace converge is Christ.</p>",
        "14": "<p>Gad camps with Reuben's standard on the south. Gad ('good fortune') joins the secondary southern camp alongside the displaced firstborn and the heard tribe. The southern camp is a cluster of tribes whose names encode hope deferred: heard but waiting, fortunate but not yet leading, firstborn but not yet first. The church in the wilderness understands this posture: 'we groan inwardly as we wait eagerly for adoption as sons, the redemption of our bodies' (Rom 8:23).</p>",
        "15": "<p>Gad's force: 45,650. The southern company's three tribes (Reuben, Simeon, Gad) total 151,450 — the second-largest marching company. The second-place position of the displaced firstborn's company is the camp order's visual theology: Jacob's firstborn lines up second behind the divinely chosen royal tribe.</p>",
        "16": "<p>Total of Reuben's standard: 151,450 — they march second. The march order traces the eschatological procession: first comes the royal tribe (Judah/Christ), then the rest of the redeemed people follow. The procession through the wilderness is the type of the church's march toward the heavenly inheritance (Heb 11:13–16: 'they were strangers and exiles on the earth... seeking a homeland').</p>",
        "17": "<p>The tent of meeting marches in the middle — between the first two and the last two companies. The tabernacle at the center of the march is the theological core of Numbers: YHWH's presence is neither at the front nor the rear but in the midst of his people. Jesus stands among the lampstands (Rev 1:13) in the same central-dwelling posture. The incarnation is the ultimate midst: God in the center of human existence.</p>",
        "18": "<p>Ephraim's standard camps on the west side. West (<i>yam</i> = sea) is the direction from which the gospel will ultimately reach all nations in Paul's western mission (Rom 15:24). Ephraim leads the western company — the younger son who inherited the greater blessing now faces the direction from which the gospel reaches the ends of the earth.</p>",
        "19": "<p>Ephraim's force: 40,500 under Elishama son of Ammihud. Elishama's name (<i>ˀelishama</i> = 'my God has heard') is the western counterpart to Simeon's 'YHWH has heard' on the south. The heard-God theme appears at multiple compass points of the camp — the refrain of divine attentiveness to human need is built into the camp's spatial structure.</p>",
        "20": "<p>Manasseh camps with Ephraim's standard on the west. The elder Manasseh follows the younger Ephraim — Jacob's hand-crossing (Gen 48:14–19) is maintained in the camp arrangement. The reversal of natural birth order in the Joseph tribes encodes the Pauline principle: 'not because of works but because of him who calls' (Rom 9:12).</p>",
        "21": "<p>Manasseh's force: 32,200 under Gamaliel son of Pedahzur. Gamaliel's name (<i>gamliˀel</i> = 'God is my reward/recompense') carries the hope that God himself is the ultimate inheritance. Moses expresses this: 'YHWH is my portion' (Ps 16:5) — the inheritance theology of Numbers points to the person of God as the true inheritance Christ brings (John 17:3: 'this is eternal life, that they know you').</p>",
        "22": "<p>Benjamin camps with Ephraim's standard on the west. Benjamin — son of the right hand — is placed in the western company with the Joseph/Rachel tribes. The right-hand positioning that Benjamin's name evokes anticipates the session of Christ: 'The LORD says to my Lord: Sit at my right hand' (Ps 110:1). From the tribe of the right hand comes the apostle who will take the gospel to the right-hand edge of the known world.</p>",
        "23": "<p>Benjamin's force: 35,400 under Abidan son of Gideoni. The Rachel-line tribes (Ephraim, Manasseh, Benjamin) form the western company. Rachel, whose weeping over her lost children is invoked at the massacre of the innocents (Matt 2:18, citing Jer 31:15), casts a mourning shadow over the western camp — yet from this same Rachel line comes the apostle whose gospel brings the 'comfort' that Jeremiah's same passage promises (Jer 31:16–17).</p>",
        "24": "<p>Total of Ephraim's standard: 108,100 — they march third. The western, Rachel-line company is the smallest of the four marching companies. Smallness in the camp does not diminish destiny: the Rachel tribes will produce the apostle who reaches the western ends of the earth (Benjamin → Paul), and the company whose name means 'doubly fruitful' (Ephraim) will bear double fruit in the gospel's global harvest.</p>",
        "25": "<p>Dan's standard camps on the north side. North in ANE cosmology is often the direction of danger and threat (Jer 1:14). Dan, the tribe associated with the serpent-path (Gen 49:17) and later with idolatry, guards the rear/north position. The most vulnerable position — guarding the rear against the northern threat — is where the subtle danger is placed and where vigilance is most required.</p>",
        "26": "<p>Dan's force: 62,700 under Ahiezer son of Ammishaddai. Dan's number is large, and his rear-guard position is honorable. The rear-guard function — protecting the vulnerable — is the role Christ himself performs for his flock: 'I give them eternal life, and they will never perish, and no one will snatch them out of my hand' (John 10:28).</p>",
        "27": "<p>Asher camps with Dan's standard on the north. The tribe of blessing and abundance (Asher = blessed) guards the northern perimeter alongside the serpentine Dan. Blessedness and vulnerability exist side by side in the covenant community — 'Blessed is the man who remains steadfast under trial, for when he has stood the test he will receive the crown of life' (Jas 1:12).</p>",
        "28": "<p>Asher's force: 41,500. The fertile, oil-rich, blessed tribe stands guard on the north. The grace of abundance does not remove the call to watchfulness. This is the pattern of Christ's own incarnation: the most blessed (the eternal Son) takes the most exposed position (human flesh, death on a cross) to guard those who cannot guard themselves.</p>",
        "29": "<p>Naphtali camps with Dan's standard on the north. The tribe of wrestling and fullness (Naphtali = 'my wrestling'; Deut 33:23 = 'satisfied with favor') joins the northern rear-guard. The wrestling-tribe in the rearguard position is fitting: holding the rear of a march through hostile wilderness requires sustained engagement — the wrestling-posture of faith that refuses to let go (Gen 32:26: 'I will not let you go unless you bless me').</p>",
        "30": "<p>Naphtali's force: 53,400. The northern rear-guard's task is to ensure no one is left behind. In Luke 15:3–7 (the lost sheep), the good shepherd leaves the ninety-nine to find the one lost — the logic of the rear-guard who will not let the last straggler fall into the enemy's hands.</p>",
        "31": "<p>Total of Dan's standard: 157,600 — they march last. 'The last shall be first and the first last' (Matt 20:16) applies to the march order: the tribes that guard the rear occupy the position from which Christ himself will come to gather the last of his flock. The rear is not the least — it is where the shepherd watches most carefully for the one who might be lost.</p>",
        "32": "<p>The registered men of Israel by their fathers' houses: 603,550. The grand total from ch 1 is confirmed in the camp-arrangement summary. The church of Christ is simultaneously counted and arranged: each member known and each one placed in the body where God determines (1 Cor 12:18: 'God arranged the members in the body, each one of them, as he chose').</p>",
        "33": "<p>The Levites were not registered among the Israelites, as YHWH commanded Moses. The tabernacle attendants are positioned separately around the sanctuary — not incorporated into the fighting-camp formations. The priestly order stands in its own spatial configuration around the holy of holies, just as Christ's priestly intercession stands in its own category: 'He always lives to make intercession' for those who draw near to God through him (Heb 7:25).</p>",
        "34": "<p>The Israelites did everything YHWH commanded Moses — they camped by their standards and set out by their clans. The compliance formula closes the camp-arrangement chapter with full obedience. The visible order of Israel — 603,550 fighting men deployed in four quadrants around the dwelling of the holy God — is the OT's most complete image of the church in formation: a vast, ordered, diverse company of pilgrims gathered around the living presence of God, marching toward the promised inheritance under his leadership. 'I saw the holy city, new Jerusalem, coming down out of heaven from God... Behold, the dwelling place of God is with man' (Rev 21:2–3).</p>",
    },
}


def main():
    data = load_comm("mkt-christ", "numbers")
    merge_comm(data, NUMBERS_CHRIST)
    save_comm("mkt-christ", "numbers", data)


if __name__ == "__main__":
    main()
